1	// Deterministic comment renderer. Takes findings + envelope + prices → comment markdown.
2	// Uses Eta templates; pure data-in, string-out — no side effects, no model invocation.
3	
4	import { Eta } from "eta";
5	import type { Finding, Severity } from "./schema.js";
6	import type { RenderInput, SeverityCounts } from "./types.js";
7	import { computeCost } from "./cost.js";
8	import { severityEmoji, findingsPointer, projectPatch, formatConfidence } from "./surface.js";
9	import type { PatchProjection } from "./surface.js";
10	
11	/** Escape pipe characters so they don't break markdown table columns. */
12	const escapePipes = (text: string): string => text.replace(/\|/g, "\\|");
13	
14	/** Replace backticks so they don't break inline code spans. */
15	const escapeCodeBackticks = (text: string): string => text.replace(/`/g, "-");
16	
17	/** A stray finding with its sanitized fields plus its projected patch block for the strays list. */
18	type StrayView = Finding & { readonly patchProjection: PatchProjection };
19	
20	/** Sanitize a stray finding's fields and attach its patch projection for the strays section. */
21	const sanitizeFinding = (f: Finding): StrayView => ({
22	  ...f,
23	  title: escapePipes(f.title),
24	  path: escapeCodeBackticks(f.path),
25	  patchProjection: projectPatch(f.patch),
26	});
27	
28	const emptySeverityCounts = (): Record<Severity, number> => ({
29	  critical: 0,
30	  major: 0,
31	  minor: 0,
32	  nit: 0,
33	});
34	
35	/** Tally findings by severity for the summary counts line. Ignores out-of-domain severities. */
36	export const computeSeverityCounts = (findings: readonly Finding[]): SeverityCounts =>
37	  findings.reduce<Record<Severity, number>>(
38	    (acc, f) => (f.severity in acc ? { ...acc, [f.severity]: acc[f.severity] + 1 } : acc),
39	    emptySeverityCounts(),
40	  );
41	
42	/** Render a code-review comment from findings, envelope, and prices. Pure. */
43	export const render = (input: RenderInput): string => {
44	  const eta = new Eta({ autoTrim: false });
45	  const usageAvailable = input.envelope !== null;
46	  const costReport = input.envelope ? computeCost(input.envelope.models, input.prices) : null;
47	  const pricesProvided = input.pricesProvided ?? true;
48	  const route = input.route ?? input.envelope?.route ?? null;
49	  const effort = input.effort ?? input.envelope?.effort ?? null;
50	  const modelNames = input.envelope ? input.envelope.models.map((m) => m.model).join(", ") : "";
51	
52	  return eta.renderString(input.template, {
53	    findings: input.findings,
54	    envelope: input.envelope,
55	    usageAvailable,
56	    costReport,
57	    pricesProvided,
58	    route,
59	    effort,
60	    modelNames,
61	    testReport: input.testReport ?? null,
62	    reviewedSha: input.reviewedSha ?? "0000000000000000000000000000000000000000",
63	    postedAt: input.postedAt ?? "",
64	    severityCounts: input.severityCounts ?? computeSeverityCounts(input.findings.findings),
65	    strays: (input.strays ?? []).map(sanitizeFinding),
66	    unanchoredCount: input.unanchoredCount ?? 0,
67	    inlineDisposition: input.inlineDisposition ?? null,
68	    runUrl: input.runUrl ?? null,
69	    jsonUrl: input.jsonUrl ?? null,
70	    findingsPointer: input.findingsPointer ?? findingsPointer(input.findings, input.jsonUrl),
71	    reviewUrl: input.reviewUrl ?? null,
72	    formatTokens: (n: number): string =>
73	      Number.isFinite(n) && n >= 0 ? n.toLocaleString("en-US") : "—",
74	    // Cost cells render N/A (never a false $0.00) when no real price map was provided — there are
75	    // real tokens spent, we simply have no rates to price them (SPEC §6.2).
76	    formatCost: (n: number): string =>
77	      !pricesProvided
78	        ? "N/A"
79	        : Number.isFinite(n)
80	          ? n > 0 && n.toFixed(2) === "0.00"
81	            ? "<$0.01"
82	            : `$${n.toFixed(2)}`
83	          : "—",
84	    formatDuration: (ms: number): string => {
85	      if (!Number.isFinite(ms) || ms < 0) return "—";
86	      const s = Math.round(ms / 1000);
87	      return s >= 60 ? `${String(Math.floor(s / 60))}m ${String(s % 60)}s` : `${String(s)}s`;
88	    },
89	    verdictBadge: (v: string): string => {
90	      switch (v) {
91	        case "approve":
92	          return "✅ approved";
93	        case "comment":
94	          return "💬 comment";
95	        case "changes":
96	          return "🔧 changes requested";
97	        default:
98	          return `❓ ${v}`;
99	      }
100	    },
101	    severityEmoji,
102	    formatConfidence,
103	  });
104	};
