587	  }
588	
589	  const findingsResult = loadFindings(input.findingsPath);
590	  if (findingsResult.kind !== "ok") {
591	    await upsertSticky(
592	      input.repo,
593	      prNumber,
594	      existingSticky,
595	      renderNotice(noticeMessageFor(findingsResult)),
596	      ghApi,
597	    );
598	    process.exit(0);
599	  }
600	  const findings = findingsResult.findings;
601	
602	  const envelope = loadEnvelope(input.envelopePath);
603	  const testReport = input.testReportPath ? loadTestReport(input.testReportPath) : undefined;
604	
605	  if (envelope === null) {
606	    const body = formatMarkdown(
607	      render({
608	        findings,
609	        envelope: null,
610	        prices: decodedPrices.right,
611	        pricesProvided: input.pricesProvided,
612	        template,
613	        route: input.route,
614	        reviewedSha: input.headSha,
615	        effort: input.effort,
616	        testReport,
617	        inlineDisposition: { kind: "no-envelope" },
618	        runUrl: input.runUrl,
619	        jsonUrl: input.jsonUrl,
620	        postedAt: input.postedAt,
621	      }),
622	    );
