1	// Pure patch helpers (issue #10): a review agent's own unified-diff patch of an edit it actually
2	// made is either validated against the real PR-head file (to align a finding's range and confirm it
3	// still applies) or projected into a GitHub suggestion's replacement text — two concerns split into
4	// two pure functions over one shared hunk parser (SSOT). Eliminates the bad-suggestion bug class
5	// caused by hand-authored suggestions with wrong indentation or too-wide ranges. Assumes LF line
6	// endings (the review runs on Linux); CRLF handling is out of scope.
7	
8	/** The outcome of validating a patch against the PR-head file: `anchored` when it applies and has a
9	 *  removed range a suggestion can replace; `keep` when it applies but has no removed range to anchor
10	 *  (a pure insertion) — the patch survives for the renderer's ```patch fallback; `drop` when it
11	 *  doesn't apply or isn't a usable single-hunk change at all. */
12	export type ValidateResult =
13	  | { readonly kind: "anchored"; readonly startLine: number; readonly endLine: number }
14	  | { readonly kind: "keep"; readonly reason: string }
15	  | { readonly kind: "drop"; readonly reason: string };
16	
17	/** The replacement text a patch's added lines carry — a suggestion's body. */
18	export type SuggestionResult = string | { readonly kind: "drop"; readonly reason: string };
19	
20	type BodyLine =
21	  | { readonly kind: "context"; readonly text: string }
22	  | { readonly kind: "removed"; readonly text: string }
23	  | { readonly kind: "added"; readonly text: string };
24	
25	const HUNK_HEADER_RE = /^@@ -(\d+)(?:,\d+)? \+\d+(?:,\d+)? @@/;
26	
27	/** The hunk's `-a` value when `line` is a hunk header, else null. */
28	const hunkOldStart = (line: string): number | null => {
29	  const raw = HUNK_HEADER_RE.exec(line)?.[1];
30	  return raw !== undefined ? Number(raw) : null;
31	};
32	
33	/** Classify one hunk-body line by its leading marker char, stripping it; null when the line
34	 *  carries none of the three markers (malformed). */
35	const classifyBodyLine = (line: string): BodyLine | null => {
36	  if (line.startsWith(" ")) return { kind: "context", text: line.slice(1) };
37	  if (line.startsWith("-")) return { kind: "removed", text: line.slice(1) };
38	  if (line.startsWith("+")) return { kind: "added", text: line.slice(1) };
39	  return null;
40	};
41	
42	/** The maximal run of non-context lines in the middle of `body`, once leading and trailing context
43	 *  is trimmed — empty when `body` is all context (no change at all). */
44	const trimmedMiddle = (body: readonly BodyLine[]): readonly BodyLine[] => {
45	  const first = body.findIndex((l) => l.kind !== "context");
46	  if (first === -1) return [];
47	  const last = body.findLastIndex((l) => l.kind !== "context");
48	  return body.slice(first, last + 1);
49	};
50	
51	/** True when `middle` (already trimmed of outer context) is zero-or-more removed lines followed by
52	 *  zero-or-more added lines, with no context and no interleaving between them. */
53	const isContiguousChange = (middle: readonly BodyLine[]): boolean => {
54	  if (middle.some((l) => l.kind === "context")) return false;
55	  const firstAdded = middle.findIndex((l) => l.kind === "added");
56	  if (firstAdded === -1) return true;
57	  return (
58	    middle.slice(0, firstAdded).every((l) => l.kind === "removed") &&
59	    middle.slice(firstAdded).every((l) => l.kind === "added")
60	  );
61	};
62	
63	interface RemovedRange {
64	  readonly lineNumber: number;
65	  readonly firstRemoved: number | null;
66	  readonly lastRemoved: number | null;
67	}
68	
69	/** Fold over the hunk body tracking the old-side line number (advanced by context and removed
70	 *  lines, not by added lines), recording the first and last removed line's number. */
71	const removedRange = (body: readonly BodyLine[], oldStart: number): RemovedRange =>
72	  body.reduce<RemovedRange>(
73	    (acc, line) =>
74	      line.kind === "added"
75	        ? acc
76	        : {
77	            lineNumber: acc.lineNumber + 1,
78	            firstRemoved:
79	              line.kind === "removed" && acc.firstRemoved === null
80	                ? acc.lineNumber
81	                : acc.firstRemoved,
82	            lastRemoved: line.kind === "removed" ? acc.lineNumber : acc.lastRemoved,
83	          },
84	    { lineNumber: oldStart, firstRemoved: null, lastRemoved: null },
85	  );
86	
87	const drop = (reason: string): { readonly kind: "drop"; readonly reason: string } => ({
88	  kind: "drop",
89	  reason,
90	});
91	
92	const keep = (reason: string): { readonly kind: "keep"; readonly reason: string } => ({
93	  kind: "keep",
94	  reason,
95	});
96	
97	type ParsedHunk =
98	  | { readonly kind: "ok"; readonly oldStart: number; readonly body: readonly BodyLine[] }
99	  | { readonly kind: "drop"; readonly reason: string };
100	
101	/** Parse a single-hunk unified diff into its old-side start line + classified body — the SSOT both
102	 *  `validatePatch` and `patchToSuggestion` share. Drops on !=1 hunk or a malformed body line. */
103	const parseHunk = (patch: string): ParsedHunk => {
104	  const rawLines = patch.split("\n");
105	  // A trailing newline in the patch text splits into a trailing "" element — not a line of content.
106	  const lines =
107	    rawLines.length > 0 && rawLines[rawLines.length - 1] === "" ? rawLines.slice(0, -1) : rawLines;
108	
109	  const headerHits = lines.reduce<readonly { readonly index: number; readonly oldStart: number }[]>(
110	    (acc, line, index) => {
111	      const oldStart = hunkOldStart(line);
112	      return oldStart !== null ? [...acc, { index, oldStart }] : acc;
113	    },
114	    [],
115	  );
116	  if (headerHits.length !== 1) {
117	    return drop(`expected exactly one hunk, got ${String(headerHits.length)}`);
118	  }
119	  const hit = headerHits[0];
120	  if (hit === undefined) return drop("malformed hunk header");
121	
122	  // Header-preceding lines (diff --git/index/---/+++) are never examined — the hunk body starts
123	  // right after the header; a trailing "\ No newline at end of file" marker carries no content.
124	  const bodyRaw = lines.slice(hit.index + 1).filter((line) => !line.startsWith("\\"));
125	  const classified = bodyRaw.map(classifyBodyLine);
126	  if (classified.some((line) => line === null)) return drop("malformed hunk body line");
127	  const body = classified.filter((line): line is BodyLine => line !== null);
128	
129	  return { kind: "ok", oldStart: hit.oldStart, body };
130	};
131	
132	/** The issue-#10 guard: confirm a single-hunk unified diff still applies to the PR-head file
133	 *  (`fileLines`, 0-indexed lines WITHOUT trailing newlines) and, when it does, anchor it — returning
134	 *  the exact `start_line..end_line` its removed lines occupy for aligning the finding's range, or
135	 *  `keep` when it applies but is a pure insertion with no removed range to anchor. Drops on a context
136	 *  mismatch, a non-contiguous change, or a hunk with no changes at all. Pure. */
137	export const validatePatch = (patch: string, fileLines: readonly string[]): ValidateResult => {
138	  const parsed = parseHunk(patch);
139	  if (parsed.kind === "drop") return parsed;
140	  const { oldStart, body } = parsed;
141	
142	  const oldSideTexts = body.filter((l) => l.kind !== "added").map((l) => l.text);
143	  const expected = fileLines.slice(oldStart - 1, oldStart - 1 + oldSideTexts.length);
144	  const oldSideMatches =
145	    expected.length === oldSideTexts.length &&
146	    expected.every((line, i) => line === oldSideTexts[i]);
147	  if (!oldSideMatches) {
148	    return drop(
149	      `patch context does not match the file at lines ${String(oldStart)}..${String(oldStart + oldSideTexts.length - 1)}`,
150	    );
151	  }
152	
153	  if (!isContiguousChange(trimmedMiddle(body))) {
154	    return drop("change is not a single contiguous block");
155	  }
156	
157	  const removedCount = body.filter((l) => l.kind === "removed").length;
158	  const addedCount = body.filter((l) => l.kind === "added").length;
159	  if (removedCount === 0 && addedCount === 0) return drop("hunk contains no changes");
160	  if (removedCount === 0) {
161	    return keep("pure insertion applies cleanly but has no removed range to anchor a suggestion");
162	  }
163	
164	  const { firstRemoved, lastRemoved } = removedRange(body, oldStart);
165	  if (firstRemoved === null || lastRemoved === null) return drop("malformed hunk body");
166	
167	  return { kind: "anchored", startLine: firstRemoved, endLine: lastRemoved };
168	};
