170	/** Project a single-hunk unified diff into a GitHub suggestion's replacement text (the added lines
171	 *  alone) — no file needed. Drops a multi-hunk/malformed patch, a non-contiguous change, or a pure
172	 *  insertion (nothing to replace). An all-deletion hunk yields "" (delete the range). Pure. */
173	export const patchToSuggestion = (patch: string): SuggestionResult => {
174	  const parsed = parseHunk(patch);
175	  if (parsed.kind === "drop") return parsed;
176	  const { body } = parsed;
177	
178	  if (!isContiguousChange(trimmedMiddle(body))) {
179	    return drop("change is not a single contiguous block");
180	  }
181	
182	  const removedCount = body.filter((l) => l.kind === "removed").length;
183	  const addedLines = body.filter((l) => l.kind === "added");
184	  if (removedCount === 0 && addedLines.length === 0) return drop("hunk contains no changes");
185	  if (removedCount === 0) return drop("pure insertion can't be expressed as a suggestion");
186	
187	  return addedLines.map((l) => l.text).join("\n");
188	};
